#!/usr/bin/env python3
"""Verifier support for the Alibaba sample `rou3-repeated-regex-modifier-constraints`.

The shell verifier embeds and applies the fail-to-pass test patch directly
so it can run in language images that may not include Python. This file
records the same check artifact in the Terminal-Bench-style location and
can write the patch when Python is available.
"""

import argparse
import base64
from pathlib import Path

PATCH_B64 = ""

def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("output", nargs="?")
    parser.add_argument("--describe", action="store_true")
    args = parser.parse_args()
    if args.describe:
        print("Fail-to-pass tests are embedded in tests/test.sh and mirror this patch artifact.")
        return 0
    output = Path(args.output or "/tmp/alibaba_test_patch.diff")
    output.write_bytes(base64.b64decode(PATCH_B64))
    print(output)
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
